import { useState } from "react";
import { useTranslation } from "react-i18next";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { AspectRatio } from "@/components/ui/aspect-ratio";
import { Film, Play, Plus, Trash2, Upload, X, ImageIcon } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";

interface VideoItem {
  url: string;
  title_zh?: string;
  title_en?: string;
  title_pt?: string;
  poster_url?: string;
  duration?: number;
}

interface RestaurantVideoManagerProps {
  bannerMediaType: 'image' | 'video';
  onBannerMediaTypeChange: (type: 'image' | 'video') => void;
  promoVideoUrl: string;
  onPromoVideoUrlChange: (url: string) => void;
  promoVideoPoster: string;
  onPromoVideoPosterChange: (url: string) => void;
  videos: VideoItem[];
  onVideosChange: (videos: VideoItem[]) => void;
}

const MAX_VIDEOS = 5;

export function RestaurantVideoManager({
  bannerMediaType,
  onBannerMediaTypeChange,
  promoVideoUrl,
  onPromoVideoUrlChange,
  promoVideoPoster,
  onPromoVideoPosterChange,
  videos,
  onVideosChange,
}: RestaurantVideoManagerProps) {
  const { t } = useTranslation();
  const { toast } = useToast();
  const [isUploading, setIsUploading] = useState(false);

  const uploadFile = async (file: File, prefix: string, isVideo: boolean = false): Promise<string> => {
    const fileExt = file.name.split(".").pop();
    const fileName = `${prefix}_${Math.random()}.${fileExt}`;
    const bucket = isVideo ? "restaurant-videos" : "restaurant-images";

    const { error: uploadError } = await supabase.storage
      .from(bucket)
      .upload(fileName, file);

    if (uploadError) throw uploadError;

    const { data: { publicUrl } } = supabase.storage
      .from(bucket)
      .getPublicUrl(fileName);

    return publicUrl;
  };

  const handlePromoVideoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    try {
      const url = await uploadFile(file, "promo_video", true);
      onPromoVideoUrlChange(url);
      toast({ title: t("common.success"), description: t("admin.videoUploaded", "视频上传成功") });
    } catch (error: any) {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
    } finally {
      setIsUploading(false);
    }
  };

  const handlePromoPosterUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    try {
      const url = await uploadFile(file, "promo_poster");
      onPromoVideoPosterChange(url);
    } catch (error: any) {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
    } finally {
      setIsUploading(false);
    }
  };

  const addVideo = () => {
    if (videos.length >= MAX_VIDEOS) return;
    onVideosChange([...videos, { url: "", title_zh: "", title_en: "", title_pt: "", poster_url: "" }]);
  };

  const removeVideo = (index: number) => {
    onVideosChange(videos.filter((_, i) => i !== index));
  };

  const updateVideo = (index: number, field: keyof VideoItem, value: string | number) => {
    const newVideos = [...videos];
    newVideos[index] = { ...newVideos[index], [field]: value };
    onVideosChange(newVideos);
  };

  const handleVideoUpload = async (index: number, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    try {
      const url = await uploadFile(file, `video_${index}`, true);
      updateVideo(index, "url", url);
      toast({ title: t("common.success"), description: t("admin.videoUploaded", "视频上传成功") });
    } catch (error: any) {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
    } finally {
      setIsUploading(false);
    }
  };

  const handleVideoPosterUpload = async (index: number, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    try {
      const url = await uploadFile(file, `video_poster_${index}`);
      updateVideo(index, "poster_url", url);
    } catch (error: any) {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
    } finally {
      setIsUploading(false);
    }
  };

  return (
    <div className="space-y-6">
      {/* Banner Media Type Selection */}
      <Card className="border-primary/20">
        <CardContent className="p-4 space-y-4">
          <Label className="text-sm font-semibold flex items-center gap-2">
            <Film className="w-4 h-4 text-primary" />
            {t("restaurants.bannerType", "横幅类型")}
          </Label>
          <RadioGroup
            value={bannerMediaType}
            onValueChange={(value) => onBannerMediaTypeChange(value as 'image' | 'video')}
            className="flex gap-4"
          >
            <div className="flex items-center space-x-2">
              <RadioGroupItem value="image" id="banner-image" />
              <Label htmlFor="banner-image" className="cursor-pointer text-sm">
                {t("restaurants.bannerImage", "图片")}
              </Label>
            </div>
            <div className="flex items-center space-x-2">
              <RadioGroupItem value="video" id="banner-video" />
              <Label htmlFor="banner-video" className="cursor-pointer text-sm">
                {t("restaurants.bannerVideo", "视频")}
              </Label>
            </div>
          </RadioGroup>

          {/* Promo Video Upload (only when video is selected) */}
          {bannerMediaType === 'video' && (
            <div className="space-y-4 pt-2">
              <p className="text-xs text-muted-foreground">
                {t("restaurants.promoVideoHint", "宣传视频将在顶部横幅位置自动静音循环播放")}
              </p>
              
              {/* Video Upload */}
              <div className="space-y-2">
                <Label className="text-sm">{t("restaurants.promoVideo", "宣传视频")}</Label>
                <div className="flex items-center gap-3">
                  {promoVideoUrl ? (
                    <div className="relative group">
                      <div className="w-40 h-24 bg-muted rounded-lg flex items-center justify-center overflow-hidden">
                        <video 
                          src={promoVideoUrl} 
                          className="w-full h-full object-cover"
                          muted
                        />
                        <div className="absolute inset-0 bg-black/30 flex items-center justify-center">
                          <Play className="w-8 h-8 text-white" fill="white" />
                        </div>
                      </div>
                      <Button
                        type="button"
                        variant="destructive"
                        size="icon"
                        className="absolute -top-2 -right-2 h-6 w-6 opacity-0 group-hover:opacity-100 transition-opacity rounded-full"
                        onClick={() => onPromoVideoUrlChange("")}
                      >
                        <X className="h-3 w-3" />
                      </Button>
                    </div>
                  ) : (
                    <Label htmlFor="promo-video-upload" className="cursor-pointer">
                      <div className="flex flex-col items-center gap-2 px-6 py-4 border-2 border-dashed border-primary/30 rounded-lg hover:border-primary hover:bg-primary/5 transition-all">
                        <Upload className="h-6 w-6 text-primary" />
                        <p className="font-medium text-xs">{t("admin.uploadVideo", "上传视频")}</p>
                      </div>
                      <Input
                        id="promo-video-upload"
                        type="file"
                        accept="video/*"
                        className="hidden"
                        onChange={handlePromoVideoUpload}
                        disabled={isUploading}
                      />
                    </Label>
                  )}
                </div>
              </div>

              {/* Video Poster Upload */}
              <div className="space-y-2">
                <Label className="text-sm">{t("restaurants.videoPoster", "视频封面")}</Label>
                <p className="text-xs text-muted-foreground">{t("restaurants.videoPosterHint", "视频加载时显示的封面图")}</p>
                <div className="flex items-center gap-3">
                  {promoVideoPoster ? (
                    <div className="relative group">
                      <img
                        src={promoVideoPoster}
                        alt="Video Poster"
                        className="w-32 h-20 object-cover rounded-lg shadow ring-2 ring-primary/20"
                      />
                      <Button
                        type="button"
                        variant="destructive"
                        size="icon"
                        className="absolute -top-2 -right-2 h-6 w-6 opacity-0 group-hover:opacity-100 transition-opacity rounded-full"
                        onClick={() => onPromoVideoPosterChange("")}
                      >
                        <X className="h-3 w-3" />
                      </Button>
                    </div>
                  ) : (
                    <Label htmlFor="promo-poster-upload" className="cursor-pointer">
                      <div className="flex flex-col items-center gap-2 px-4 py-3 border-2 border-dashed border-muted-foreground/30 rounded-lg hover:border-primary/50 transition-all">
                        <ImageIcon className="h-5 w-5 text-muted-foreground" />
                        <p className="font-medium text-xs text-muted-foreground">{t("admin.uploadImage")}</p>
                      </div>
                      <Input
                        id="promo-poster-upload"
                        type="file"
                        accept="image/*"
                        className="hidden"
                        onChange={handlePromoPosterUpload}
                        disabled={isUploading}
                      />
                    </Label>
                  )}
                </div>
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Video Gallery Section */}
      <Card className="border-primary/20">
        <CardContent className="p-4 space-y-4">
          <div className="flex items-center justify-between">
            <Label className="text-sm font-semibold flex items-center gap-2">
              <Play className="w-4 h-4 text-primary" />
              {t("restaurants.videoGallery", "视频列表")}
            </Label>
            <span className="text-xs text-muted-foreground">
              {t("restaurants.maxVideos", { count: MAX_VIDEOS })}
            </span>
          </div>
          
          <p className="text-xs text-muted-foreground">
            {t("restaurants.videoGalleryHint", "添加美食制作过程、品牌故事等视频")}
          </p>

          {/* Video List */}
          <div className="space-y-4">
            {videos.map((video, index) => (
              <div key={index} className="p-4 border rounded-lg space-y-3 bg-muted/30">
                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium">{t("common.video", "视频")} #{index + 1}</span>
                  <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    onClick={() => removeVideo(index)}
                    className="text-destructive hover:text-destructive"
                  >
                    <Trash2 className="w-4 h-4" />
                  </Button>
                </div>

                {/* Video Upload */}
                <div className="space-y-3">
                  <div className="flex items-center gap-3">
                    {video.url ? (
                      <div className="relative group">
                        <div className="w-32 h-20 bg-muted rounded-lg flex items-center justify-center overflow-hidden">
                          <video 
                            src={video.url} 
                            className="w-full h-full object-cover"
                            muted
                          />
                          <div className="absolute inset-0 bg-black/30 flex items-center justify-center">
                            <Play className="w-6 h-6 text-white" fill="white" />
                          </div>
                        </div>
                        <Button
                          type="button"
                          variant="destructive"
                          size="icon"
                          className="absolute -top-2 -right-2 h-5 w-5 opacity-0 group-hover:opacity-100 transition-opacity rounded-full"
                          onClick={() => updateVideo(index, "url", "")}
                        >
                          <X className="h-3 w-3" />
                        </Button>
                      </div>
                    ) : (
                      <Label htmlFor={`video-upload-${index}`} className="cursor-pointer">
                        <div className="flex flex-col items-center gap-1 px-4 py-3 border-2 border-dashed border-primary/30 rounded-lg hover:border-primary hover:bg-primary/5 transition-all">
                          <Upload className="h-5 w-5 text-primary" />
                          <p className="font-medium text-xs">{t("admin.uploadVideo", "上传视频")}</p>
                        </div>
                        <Input
                          id={`video-upload-${index}`}
                          type="file"
                          accept="video/*"
                          className="hidden"
                          onChange={(e) => handleVideoUpload(index, e)}
                          disabled={isUploading}
                        />
                      </Label>
                    )}

                    {/* Poster Upload - Required */}
                    {video.poster_url ? (
                      <div className="relative group">
                        <img
                          src={video.poster_url}
                          alt="Poster"
                          className="w-20 h-20 object-cover rounded-lg ring-2 ring-primary/20"
                        />
                        <Button
                          type="button"
                          variant="destructive"
                          size="icon"
                          className="absolute -top-2 -right-2 h-5 w-5 opacity-0 group-hover:opacity-100 transition-opacity rounded-full"
                          onClick={() => updateVideo(index, "poster_url", "")}
                        >
                          <X className="h-3 w-3" />
                        </Button>
                      </div>
                    ) : (
                      <Label htmlFor={`poster-upload-${index}`} className="cursor-pointer">
                        <div className={`flex flex-col items-center gap-1 px-3 py-2 border-2 border-dashed rounded-lg transition-all ${video.url ? 'border-destructive/50 bg-destructive/5' : 'border-muted-foreground/30 hover:border-primary/50'}`}>
                          <ImageIcon className={`h-4 w-4 ${video.url ? 'text-destructive' : 'text-muted-foreground'}`} />
                          <p className={`text-xs ${video.url ? 'text-destructive font-medium' : 'text-muted-foreground'}`}>
                            {t("restaurants.videoPoster", "封面")}
                            {video.url && <span className="text-destructive">*</span>}
                          </p>
                        </div>
                        <Input
                          id={`poster-upload-${index}`}
                          type="file"
                          accept="image/*"
                          className="hidden"
                          onChange={(e) => handleVideoPosterUpload(index, e)}
                          disabled={isUploading}
                        />
                      </Label>
                    )}
                  </div>
                  
                  {/* Required poster warning */}
                  {video.url && !video.poster_url && (
                    <p className="text-xs text-destructive flex items-center gap-1">
                      <span>⚠️</span>
                      {t("restaurants.posterRequired", "请上传视频封面图，用于在列表中展示")}
                    </p>
                  )}
                </div>

                {/* Video Titles (Tri-lingual) */}
                <Tabs defaultValue="zh" className="w-full">
                  <TabsList className="grid w-full grid-cols-3 h-8">
                    <TabsTrigger value="zh" className="text-xs">🇨🇳</TabsTrigger>
                    <TabsTrigger value="en" className="text-xs">🇬🇧</TabsTrigger>
                    <TabsTrigger value="pt" className="text-xs">🇵🇹</TabsTrigger>
                  </TabsList>
                  <TabsContent value="zh" className="mt-2">
                    <Input
                      value={video.title_zh || ""}
                      onChange={(e) => updateVideo(index, "title_zh", e.target.value)}
                      placeholder={t("restaurants.videoTitle", "视频标题") + " (中文)"}
                      className="text-sm"
                    />
                  </TabsContent>
                  <TabsContent value="en" className="mt-2">
                    <Input
                      value={video.title_en || ""}
                      onChange={(e) => updateVideo(index, "title_en", e.target.value)}
                      placeholder="Video Title (English)"
                      className="text-sm"
                    />
                  </TabsContent>
                  <TabsContent value="pt" className="mt-2">
                    <Input
                      value={video.title_pt || ""}
                      onChange={(e) => updateVideo(index, "title_pt", e.target.value)}
                      placeholder="Título do Vídeo (Português)"
                      className="text-sm"
                    />
                  </TabsContent>
                </Tabs>

                {/* Duration */}
                <div className="flex items-center gap-2">
                  <Label className="text-xs text-muted-foreground">{t("common.duration", "时长")} (s):</Label>
                  <Input
                    type="number"
                    value={video.duration || ""}
                    onChange={(e) => updateVideo(index, "duration", parseInt(e.target.value) || 0)}
                    placeholder="90"
                    className="w-20 h-8 text-sm"
                  />
                </div>
              </div>
            ))}
          </div>

          {/* Add Video Button */}
          {videos.length < MAX_VIDEOS && (
            <Button
              type="button"
              variant="outline"
              onClick={addVideo}
              className="w-full gap-2"
            >
              <Plus className="w-4 h-4" />
              {t("restaurants.addVideo", "添加视频")}
            </Button>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

export default RestaurantVideoManager;
