import { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Card, CardContent } from "@/components/ui/card";
import { Loader2, Sparkles, RotateCcw, Check, X, BookOpen } from "lucide-react";
import { toast } from "sonner";

interface Props {
  restaurantId: string;
  restaurantName: string;
}

/** Extract I Ching section from a photo_story text */
function extractIChing(text: string | null): string | null {
  if (!text) return null;
  const normalized = text.replace(/\\n/g, "\n");
  // Find first 《易经 or 《易經 marker
  const idx = normalized.search(/《易[经經]/);
  if (idx === -1) return null;
  return normalized.substring(idx).trim();
}

export default function IChingRegenerateSection({ restaurantId, restaurantName }: Props) {
  const { t } = useTranslation();
  const [currentIChing, setCurrentIChing] = useState<string | null>(null);
  const [newIChing, setNewIChing] = useState<string | null>(null);
  const [customPrompt, setCustomPrompt] = useState("");
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [storyZh, setStoryZh] = useState<string | null>(null);
  const [storyEn, setStoryEn] = useState<string | null>(null);
  const [storyPt, setStoryPt] = useState<string | null>(null);

  // Load current story
  useEffect(() => {
    if (!restaurantId) return;
    (async () => {
      const { data } = await supabase
        .from("restaurants")
        .select("photo_story_zh, photo_story_en, photo_story_pt")
        .eq("id", restaurantId)
        .single();
      if (data) {
        setStoryZh((data as any).photo_story_zh);
        setStoryEn((data as any).photo_story_en);
        setStoryPt((data as any).photo_story_pt);
        setCurrentIChing(extractIChing((data as any).photo_story_zh));
      }
    })();
  }, [restaurantId]);

  const handleGenerate = async () => {
    setLoading(true);
    setNewIChing(null);
    try {
      const { data, error } = await supabase.functions.invoke("generate-store-stories", {
        body: {
          mode: "regenerate_iching",
          restaurant_id: restaurantId,
          custom_prompt: customPrompt || undefined,
        },
      });

      if (error) throw error;
      if (data?.iching) {
        setNewIChing(data.iching);
        toast.success(t("admin.ichingGenerated", "易经生成成功"));
      } else {
        toast.error(data?.error || t("admin.ichingGenerateFailed", "生成失败，请重试"));
      }
    } catch (e: any) {
      console.error("Generate I Ching error:", e);
      toast.error(t("admin.ichingGenerateFailed", "生成失败，请重试"));
    } finally {
      setLoading(false);
    }
  };

  /** Replace I Ching section in a story text */
  const replaceIChing = (text: string | null, newIChingText: string): string | null => {
    if (!text) return null;
    const normalized = text.replace(/\\n/g, "\n");
    const idx = normalized.search(/《易[经經]/);
    if (idx !== -1) {
      const before = normalized.substring(0, idx).replace(/[\n\r\s]+$/, "");
      return before + "\n\n" + newIChingText;
    }
    // Append if not found
    const hasEnd = /[。！？.!?]$/.test(normalized.trim());
    return `${hasEnd ? normalized.trim() : normalized.trim() + "。"}\n\n${newIChingText}`;
  };

  const handleApply = async () => {
    if (!newIChing) return;
    setSaving(true);
    try {
      const updatedZh = replaceIChing(storyZh, newIChing);
      const updatedEn = replaceIChing(storyEn, newIChing);
      const updatedPt = replaceIChing(storyPt, newIChing);

      const { error } = await supabase
        .from("restaurants")
        .update({
          photo_story_zh: updatedZh,
          photo_story_en: updatedEn,
          photo_story_pt: updatedPt,
        } as any)
        .eq("id", restaurantId);

      if (error) throw error;

      setStoryZh(updatedZh);
      setStoryEn(updatedEn);
      setStoryPt(updatedPt);
      setCurrentIChing(newIChing);
      setNewIChing(null);
      toast.success(t("admin.ichingApplied", "易经已更新"));
    } catch (e: any) {
      console.error("Apply I Ching error:", e);
      toast.error(t("admin.ichingApplyFailed", "保存失败"));
    } finally {
      setSaving(false);
    }
  };

  return (
    <Card className="border-amber-500/30 bg-amber-50/5">
      <CardContent className="p-5 space-y-4">
        <Label className="text-base font-semibold flex items-center gap-2">
          <BookOpen className="w-5 h-5 text-amber-600" />
          {t("admin.ichingRegenerate", "易经卦象")}
        </Label>

        {/* Current I Ching */}
        <div className="space-y-1.5">
          <Label className="text-xs text-muted-foreground font-medium">
            {t("admin.currentIChing", "当前易经")}
          </Label>
          <div className="p-3 rounded-lg bg-muted/50 border text-sm min-h-[60px] whitespace-pre-wrap">
            {currentIChing || (
              <span className="text-muted-foreground italic">
                {t("admin.noIChing", "暂无易经内容")}
              </span>
            )}
          </div>
        </div>

        {/* Custom prompt */}
        <div className="space-y-1.5">
          <Label className="text-xs text-muted-foreground font-medium">
            {t("admin.ichingPromptHint", "自定义提示词（可选）")}
          </Label>
          <Textarea
            value={customPrompt}
            onChange={(e) => setCustomPrompt(e.target.value)}
            placeholder={t("admin.ichingPromptPlaceholder", "例如：希望与水相关的卦象，或与家庭团聚主题相关...")}
            rows={2}
            className="text-sm"
          />
        </div>

        {/* Generate button */}
        <Button
          type="button"
          variant="outline"
          onClick={handleGenerate}
          disabled={loading}
          className="border-amber-500/50 text-amber-700 hover:bg-amber-50"
        >
          {loading ? (
            <Loader2 className="w-4 h-4 animate-spin mr-2" />
          ) : (
            <Sparkles className="w-4 h-4 mr-2" />
          )}
          {loading
            ? t("admin.generating", "生成中...")
            : t("admin.generateNewIChing", "生成新易经")}
        </Button>

        {/* New I Ching preview + actions */}
        {newIChing && (
          <div className="space-y-3 animate-in fade-in slide-in-from-bottom-2 duration-300">
            <Label className="text-xs font-medium text-amber-700 flex items-center gap-1">
              <Sparkles className="w-3.5 h-3.5" />
              {t("admin.newIChing", "新生成的易经")}
            </Label>
            <div className="p-3 rounded-lg bg-amber-50/50 border border-amber-300/50 text-sm whitespace-pre-wrap">
              {newIChing}
            </div>
            <div className="flex gap-2">
              <Button
                type="button"
                size="sm"
                onClick={handleApply}
                disabled={saving}
                className="bg-amber-600 hover:bg-amber-700 text-white"
              >
                {saving ? (
                  <Loader2 className="w-4 h-4 animate-spin mr-1" />
                ) : (
                  <Check className="w-4 h-4 mr-1" />
                )}
                {t("admin.applyIChing", "应用此易经")}
              </Button>
              <Button
                type="button"
                size="sm"
                variant="ghost"
                onClick={handleGenerate}
                disabled={loading}
              >
                <RotateCcw className="w-4 h-4 mr-1" />
                {t("admin.regenerate", "重新生成")}
              </Button>
              <Button
                type="button"
                size="sm"
                variant="ghost"
                onClick={() => setNewIChing(null)}
              >
                <X className="w-4 h-4 mr-1" />
                {t("common.cancel", "取消")}
              </Button>
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
}
